export default function PaymentsPage() {
  return (
    <div className="p-8">
      <h1 className="text-3xl font-bold">
        Payments
      </h1>

      <div className="mt-6 rounded-lg border p-6">
        <h2 className="text-xl">
          Outstanding Amount
        </h2>

        <p className="text-4xl font-bold mt-4">
          ₹0
        </p>

        <img
          src="/upi-qr.png"
          alt="UPI QR"
          className="w-64 mt-6"
        />

        <p className="mt-4">
          UPI ID:
          smartparking@upi
        </p>
      </div>
    </div>
  )
}